nodes.notes:
POST /pipeline/avancar { video_id }
Read-only: lê status das cenas e retorna próxima tela.
Não dispara módulos nem marca status.

Ordem de prioridade:
1. imagem != aprovada → /imagens/{id}
2. tts != aprovada → /narracao/{id}
3. efeito|video != aprovada → /preview/{id}
4. tudo aprovada → /preview/{id} (com montagem liberada)

parameters.jsCode:
const item = $input.first().json;
const video_id = item.video_id || (item.body && item.body.video_id) || null;
if (!video_id) throw new Error('video_id obrigatório.');
return [{ json: { video_id } }];

// ===================================================================
// DECIDIR PRÓXIMA TELA — Pipeline Avançar
// ===================================================================
// Lê todas as cenas do vídeo e determina o próximo frontend
// baseado no status dos módulos. Não escreve nada, só lê.
// ===================================================================

const config = $('Configuração').first().json;
const video_id = $('Normalizar Input').first().json.video_id;

const headers = {
  apikey: config.SUPABASE_SERVICE_KEY,
  Authorization: 'Bearer ' + config.SUPABASE_SERVICE_KEY
};

const cenas = await this.helpers.httpRequest({
  method: 'GET',
  url: config.SUPABASE_URL + '/rest/v1/cenas?video_id=eq.' + video_id + '&opcao_id=is.null&select=numero,tipo_cena,imagem_status,tts_status,efeito_status,video_status',
  headers,
  json: true
});

// Ignora cenas tipo_cena='texto' (não entram na cadeia de regeneração)
const cenasRelevantes = (cenas || []).filter(c => c.tipo_cena !== 'texto');

if (cenasRelevantes.length === 0) {
  return [{ json: { success: false, erro: 'Nenhuma cena encontrada para este vídeo' } }];
}

// Ordem de prioridade: imagem → tts → (efeito|video)
const temImagemPendente = cenasRelevantes.some(c => c.imagem_status !== 'aprovada');
const temTtsPendente = cenasRelevantes.some(c => c.tts_status !== 'aprovada');
const temEfeitoPendente = cenasRelevantes.some(c => c.efeito_status !== 'aprovada');
const temVideoPendente = cenasRelevantes.some(c => c.video_status !== 'aprovada');

let proximaTela;
let motivo;

if (temImagemPendente) {
  proximaTela = '/imagens/' + video_id;
  motivo = 'imagem';
} else if (temTtsPendente) {
  proximaTela = '/narracao/' + video_id;
  motivo = 'tts';
} else if (temEfeitoPendente || temVideoPendente) {
  proximaTela = '/preview/' + video_id;
  motivo = temEfeitoPendente && temVideoPendente ? 'efeito+video' : (temEfeitoPendente ? 'efeito' : 'video');
} else {
  // Tudo aprovada → preview com montagem liberada
  proximaTela = '/preview/' + video_id;
  motivo = 'tudo_aprovado';
}

return [{
  json: {
    success: true,
    proximaTela,
    motivo,
    totalCenas: cenasRelevantes.length
  }
}];

